class Node:
    def __init__(self, data):
        self.left = None
        self.right = None
        self.data = data.lower()

def insert(root, data):
    if root is None:
        return Node(data)
    if data < root.data:
        root.left = insert(root.left, data)
    else:
        root.right = insert(root.right, data)
    return root

def process_characters(sequence, index=0, root=None):
    if index >= len(sequence):
        return root
    current_char = sequence[index].lower()
    root = insert(root, current_char)
    return process_characters(sequence, index + 1, root)

